import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormDisciplina({ onNovaDisciplina, disciplinaEditando, onFimEdicao }) {
  const [nome, setNome] = useState('');
  const [mensagem, setMensagem] = useState('');
  const [periodos, setPeriodos] = useState([]);
  const [periodoId, setPeriodoId] = useState('');

  useEffect(() => {
    axios.get('/api/periodos')
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  }, []);

  useEffect(() => {
    if (disciplinaEditando) {
      setNome(disciplinaEditando.nome);
      setPeriodoId(disciplinaEditando.periodo_id || '');
    } else {
      setNome('');
      setPeriodoId('');
    }
  }, [disciplinaEditando]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (disciplinaEditando) {
      axios.put(`/api/disciplinas/${disciplinaEditando.id}`, { nome, periodo_id: periodoId })
        .then(() => {
          setMensagem('Disciplina atualizada!');
          setNome('');
          setPeriodoId('');
          onNovaDisciplina();
          onFimEdicao();
        })
        .catch(() => setMensagem('Erro ao atualizar disciplina.'));
    } else {
      axios.post('/api/disciplinas', { nome, periodo_id: periodoId })
        .then(() => {
          setMensagem('Disciplina cadastrada!');
          setNome('');
          setPeriodoId('');
          onNovaDisciplina();
        })
        .catch(() => setMensagem('Erro ao cadastrar disciplina.'));
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{marginBottom: 24}}>
      <h2>{disciplinaEditando ? 'Editar Disciplina' : 'Cadastrar Nova Disciplina'}</h2>
      <div>
        <label>
          Nome:
          <input value={nome} onChange={e => setNome(e.target.value)} required />
        </label>
      </div>
      <div>
        <label>
          Período:
          <select
            value={periodoId}
            onChange={e => setPeriodoId(e.target.value)}
            required
          >
            <option value="">Selecione um período</option>
            {periodos.map(periodo => (
              <option key={periodo.id} value={periodo.id}>
                {periodo.nome}
              </option>
            ))}
          </select>
        </label>
      </div>
      <button type="submit">{disciplinaEditando ? 'Atualizar' : 'Cadastrar'}</button>
      {disciplinaEditando && <button type="button" onClick={onFimEdicao}>Cancelar</button>}
      {mensagem && <p>{mensagem}</p>}
    </form>
  );
}

export default FormDisciplina;
